// A CapabilitySet is the library's entire input — built fluently.
let caps = CapabilitySet::new()
    // read-only access to the project directory
    .allow_path("/work/project", AccessMode::Read)?
    // read-write to a single scratch file
    .allow_file("/work/agent.log", AccessMode::ReadWrite)?
    // deny the network outright...
    .block_network()
    // ...or force every connection through the audited proxy
    .proxy_only(8080);

// One call. After this line, the kernel is in charge.
Sandbox::apply(&caps)?;
